<?php defined('ABSPATH') || exit; class FounderKit_Settings { const OPTION_KEY='founderkit_settings'; public static function defaults(): array { $defaults=['gsap_enabled'=>true,'animation_intensity'=>'medium','color_accent'=>'#00d4c8','color_accent_2'=>'#e8b44a','woo_integration'=>true,'ld_integration'=>true,'enable_rest_api'=>false,'remove_on_uninstall'=>false,'enabled_blocks'=>['fk-hero'=>1,'fk-stats-counter'=>1,'fk-case-study'=>1,'fk-portfolio-grid'=>1,'fk-tech-stack'=>1,'fk-pricing-table'=>1,'fk-quiz-embed'=>1,'fk-course-card'=>1,'fk-timeline'=>1,'fk-digital-product-card'=>1,'fk-testimonial-carousel'=>1,'fk-job-listing'=>1,'fk-team-member'=>1,'fk-membership-cta'=>1,'fk-resource-card'=>1],'active_addons'=>[]]; return apply_filters('founderkit_settings_defaults',$defaults); } public static function activate_defaults(): void { do_action('founderkit_before_activate_defaults'); if(!get_option(self::OPTION_KEY)) add_option(self::OPTION_KEY,self::defaults()); do_action('founderkit_after_activate_defaults'); } public function all(): array { do_action('founderkit_before_load_settings'); $settings=wp_parse_args(get_option(self::OPTION_KEY,[]), self::defaults()); return apply_filters('founderkit_loaded_settings',$settings); } public function get(string $key){ $all=$this->all(); $value=$all[$key]??null; return apply_filters('founderkit_get_setting_'.$key,$value,$key,$all); } public function update(array $data): bool { do_action('founderkit_before_update_settings',$data); $data=apply_filters('founderkit_update_settings_data',$data); $result=update_option(self::OPTION_KEY,array_merge($this->all(),$data)); do_action('founderkit_after_update_settings',$data,$result); return $result; } public function is_block_enabled(string $slug): bool { $all=$this->all(); $enabled=!empty($all['enabled_blocks'][$slug]); return apply_filters('founderkit_is_block_enabled',$enabled,$slug); } public function get_all_blocks(): array { $all=$this->all(); return $all['enabled_blocks']??[]; } public function set_block(string $slug,bool $state): bool { do_action('founderkit_before_set_block',$slug,$state); $all=$this->all(); $all['enabled_blocks'][$slug]=$state?1:0; $result=update_option(self::OPTION_KEY,$all); do_action('founderkit_after_set_block',$slug,$state,$result); return $result; } }
